public class ThisCall {
    int a, b;
    ThisCall(int a) { this(a, 0); System.out.println("1-arg"); }
    ThisCall(int a, int b) { this.a = a; this.b = b; System.out.println("2-arg"); }
    public static void main(String[] args) {
        ThisCall t = new ThisCall(5);
        System.out.println(t.a + " " + t.b);
    }
}
